// runRoutePreflightBounded runs fn under a route-resolution deadline, returning
// timedOut=true only when the deadline fired before fn returned. fn runs in a
// goroutine so a preflight resolver that ignores context cancellation cannot
// wedge the worker past the timeout.
func runRoutePreflightBounded(ctx context.Context, timeout time.Duration, fn func(ctx context.Context) error) (err error, timedOut bool) {
	tctx, cancel := context.WithTimeout(ctx, timeout)
	defer cancel()
	done := make(chan error, 1)
	go func() { done <- fn(tctx) }()
	select {
	case e := <-done:
		return e, false
	case <-tctx.Done():
		return tctx.Err(), errors.Is(tctx.Err(), context.DeadlineExceeded)
	}
}

// runPostCommitReviewLandBounded runs fn under a post-commit review+land deadline.
// The work is invoked in a goroutine and selected against the deadline so a
// hanging reviewer or stalled close cannot wedge the single-threaded worker past
// the timeout (ddx-b2846610). timedOut is true only when the deadline fired
// before fn returned; a parent-context cancellation reports timedOut=false.
func runPostCommitReviewLandBounded(
	ctx context.Context,
	timeout time.Duration,
	fn func(ctx context.Context) PostMergeReviewOutput,
) (out PostMergeReviewOutput, timedOut bool) {
	tctx, cancel := context.WithTimeout(ctx, timeout)
	defer cancel()
	type reviewResult struct {
		out PostMergeReviewOutput
	}
	done := make(chan reviewResult, 1)
	go func() { done <- reviewResult{out: fn(tctx)} }()
	select {
	case res := <-done:
		return res.out, false
	case <-tctx.Done():
		return PostMergeReviewOutput{}, errors.Is(tctx.Err(), context.DeadlineExceeded)
	}
}

