func TestExecuteBead_PostCommitReviewLandTimeoutReleasesLease(t *testing.T) {
	fixture, cleanup := newFixture(t, false)
	defer cleanup()

	// Create a bead that will succeed and enter post-merge review
	_, candidate := fixture.createSimpleTestBead(t, "post-commit-timeout-test")

	rcfg := config.NewTestConfigForLoop(config.TestLoopConfigOpts{Assignee: "test-worker"}).
		Resolve(config.TestLoopOverrides(config.TestLoopConfigOpts{Assignee: "test-worker"}))

	// Create a reviewer that hangs
	hangingReviewer := &stubReviewer{
		hangFor: 5 * time.Second,
	}

	runtime := ExecuteBeadLoopRuntime{
		Log:                            os.Stderr,
		ProjectRoot:                    fixture.dir,
		PostMergeReview:                true,
		NoReview:                       false,
		PostCommitReviewLandTimeout:    500 * time.Millisecond, // Very short timeout for testing
		IgnoreCooldown:                 true,
		SessionID:                      "test-session",
		WorkerID:                       "test-worker",
		Mode:                           executeloop.ModeOnce,
	}

	worker := &ExecuteBeadWorker{
		Store:    fixture.store,
		Reviewer: hangingReviewer,
		Log:      os.Stderr,
	}

	// Run the worker with the test bead
	result, err := worker.Run(context.Background(), rcfg, runtime, fixture.store.ReadyIndex, "")

	// Should have failed with timeout
	require.NoError(t, err)
	require.NotNil(t, result)

	// Check that a timeout report was created
	assert.Equal(t, 1, len(result.Results))
	if len(result.Results) > 0 {
		report := result.Results[0]
		assert.Equal(t, ExecuteBeadStatusExecutionFailed, report.Status)
		assert.Equal(t, FailureModePostCommitReviewLandTimeout, report.OutcomeReason)
	}

	// Check that the lease was released
	events, err := fixture.store.Events(candidate.ID)
	require.NoError(t, err)
	operatorAttentionFound := false
	for _, ev := range events {
		if ev.Kind == "operator_attention" && ev.Summary == FailureModePostCommitReviewLandTimeout {
			operatorAttentionFound = true
			var body map[string]any
			err := json.Unmarshal([]byte(ev.Body), &body)
			require.NoError(t, err)
			assert.Equal(t, FailureModePostCommitReviewLandTimeout, body["reason"])
			break
		}
	}
	assert.True(t, operatorAttentionFound, "operator_attention event not found")
}

func TestExecuteBead_PostCommitReviewLandWithinBudgetCompletes(t *testing.T) {
	fixture, cleanup := newFixture(t, false)
	defer cleanup()

	_, candidate := fixture.createSimpleTestBead(t, "post-commit-no-timeout-test")

	rcfg := config.NewTestConfigForLoop(config.TestLoopConfigOpts{Assignee: "test-worker"}).
		Resolve(config.TestLoopOverrides(config.TestLoopConfigOpts{Assignee: "test-worker"}))

	// Create a reviewer that completes quickly
	fastReviewer := &stubReviewer{
		result: &ReviewResult{
			Verdict:   VerdictApprove,
			Rationale: "looks good",
		},
	}

	runtime := ExecuteBeadLoopRuntime{
		Log:                            os.Stderr,
		ProjectRoot:                    fixture.dir,
		PostMergeReview:                true,
		NoReview:                       false,
		PostCommitReviewLandTimeout:    10 * time.Second, // Generous timeout
		IgnoreCooldown:                 true,
		SessionID:                      "test-session",
		WorkerID:                       "test-worker",
		Mode:                           executeloop.ModeOnce,
	}

	worker := &ExecuteBeadWorker{
		Store:    fixture.store,
		Reviewer: fastReviewer,
		Log:      os.Stderr,
	}

	result, err := worker.Run(context.Background(), rcfg, runtime, fixture.store.ReadyIndex, "")

	// Should have succeeded
	require.NoError(t, err)
	require.NotNil(t, result)
	assert.Equal(t, 1, result.Successes)

	// Check that the bead was closed
	closed, err := fixture.store.IsClosed(candidate.ID)
	require.NoError(t, err)
	assert.True(t, closed)
}

// stubReviewer is a test stub that can hang or complete quickly
type stubReviewer struct {
	result  *ReviewResult
	hangFor time.Duration
}

func (s *stubReviewer) ReviewBead(ctx context.Context, beadID, resultRev string, impl ImplementerRouting) (*ReviewResult, error) {
	if s.hangFor > 0 {
		select {
		case <-time.After(s.hangFor):
			return s.result, nil
		case <-ctx.Done():
			return nil, ctx.Err()
		}
	}
	return s.result, nil
}

