func TestRunPostCommitReviewLandBounded_CompletesWithinTimeout(t *testing.T) {
	ctx := context.Background()
	timeout := 1 * time.Second

	output := runPostCommitReviewLandBounded(ctx, timeout, func(c context.Context) PostMergeReviewOutput {
		return PostMergeReviewOutput{
			Report: ExecuteBeadReport{
				Status: ExecuteBeadStatusSuccess,
			},
			Approved: true,
		}
	})

	assert.False(t, output.Report.Status == "") // Should have gotten a result
	assert.True(t, output.Approved)
}

func TestRunPostCommitReviewLandBounded_TimesOutWhenExceeded(t *testing.T) {
	ctx := context.Background()
	timeout := 100 * time.Millisecond

	timedOut := false
	output := runPostCommitReviewLandBounded(ctx, timeout, func(c context.Context) PostMergeReviewOutput {
		select {
		case <-time.After(500 * time.Millisecond):
			return PostMergeReviewOutput{Approved: true}
		case <-c.Done():
			timedOut = true
			return PostMergeReviewOutput{}
		}
	})

	// The timeout should fire and we should get a zero output
	assert.True(t, timedOut)
	assert.False(t, output.Approved)
}

func TestRunPostCommitReviewLandBounded_RespectsContextCancellation(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	timeout := 10 * time.Second

	// Cancel the context before running
	cancel()

	output := runPostCommitReviewLandBounded(ctx, timeout, func(c context.Context) PostMergeReviewOutput {
		return PostMergeReviewOutput{Approved: true}
	})

	// Should return empty output because context was already cancelled
	assert.False(t, output.Approved)
}

func TestPostCommitReviewLandTimeoutReport_ReleasesLeaseAndEmitsEvent(t *testing.T) {
	store := &stubBeadStore{
		events: make(map[string][]bead.BeadEvent),
	}

	report := postCommitReviewLandTimeoutReport(
		store,
		"test-bead-123",
		"test-worker",
		"attempt-456",
		time.Now(),
		15*time.Minute,
	)

	// Verify report is correct
	assert.Equal(t, "test-bead-123", report.BeadID)
	assert.Equal(t, ExecuteBeadStatusExecutionFailed, report.Status)
	assert.Equal(t, FailureModePostCommitReviewLandTimeout, report.OutcomeReason)
	assert.Contains(t, report.Detail, "post-commit review and/or land exceeded")
	assert.Contains(t, report.Detail, "15m0s")

	// Verify operator_attention event was recorded
	events := store.events["test-bead-123"]
	require.NotEmpty(t, events)

	attentionEvent := events[len(events)-1]
	assert.Equal(t, "operator_attention", attentionEvent.Kind)
	assert.Equal(t, FailureModePostCommitReviewLandTimeout, attentionEvent.Summary)

	// Verify event body contains expected fields
	var body map[string]any
	err := json.Unmarshal([]byte(attentionEvent.Body), &body)
	require.NoError(t, err)
	assert.Equal(t, FailureModePostCommitReviewLandTimeout, body["reason"])
	assert.Equal(t, "test-bead-123", body["bead_id"])
	assert.Equal(t, "attempt-456", body["attempt_id"])
}

func TestDefaultPostCommitReviewLandTimeout_IsConfigured(t *testing.T) {
	assert.Equal(t, 15*time.Minute, DefaultPostCommitReviewLandTimeout)
}

func TestExecuteBeadLoopRuntime_EffectivePostCommitReviewLandTimeout(t *testing.T) {
	tests := []struct {
		name     string
		timeout  time.Duration
		expected time.Duration
	}{
		{"zero uses default", 0, DefaultPostCommitReviewLandTimeout},
		{"positive value is used", 5 * time.Minute, 5 * time.Minute},
		{"large timeout is used", 1 * time.Hour, 1 * time.Hour},
